+// mean([1, 2, 3, 4]) => 2.5
+// mean([5])          => 5
+function mean(nums) {
+  if (!Array.isArray(nums) || nums.length === 0) throw new Error('mean requires a non-empty array');
+  return nums.reduce((sum, n) => sum + n, 0) / nums.length;
+}
+
+// mode([1, 2, 2, 3])    => [2]
+// mode([1, 1, 2, 2, 3]) => [1, 2]
+// mode([5])             => [5]
+function mode(nums) {
+  if (!Array.isArray(nums) || nums.length === 0) throw new Error('mode requires a non-empty array');
+  const freq = new Map();
+  for (const n of nums) freq.set(n, (freq.get(n) ?? 0) + 1);
+  const max = Math.max(...freq.values());
+  return [...freq.entries()].filter(([, count]) => count === max).map(([n]) => n);
+}
+
+module.exports = { median, mean, mode };
