+const { test } = require('node:test');
+const assert = require('node:assert/strict');
+const { median, mean, mode } = require('./stats');
+const { slugify, capitalize, truncate, camelCase } = require('./utils');
+
+// stats
+test('median odd-length array', () => assert.equal(median([3, 1, 4, 1, 5]), 3));
+test('median even-length array', () => assert.equal(median([1, 2, 3, 4]), 2.5));
+test('median single element', () => assert.equal(median([7]), 7));
+test('median throws on empty', () => assert.throws(() => median([])));
+test('median throws on non-array', () => assert.throws(() => median(null)));
+
+test('mean basic', () => assert.equal(mean([1, 2, 3, 4]), 2.5));
+test('mean single element', () => assert.equal(mean([5]), 5));
+test('mean throws on empty', () => assert.throws(() => mean([])));
+
+test('mode single mode', () => assert.deepEqual(mode([1, 2, 2, 3]), [2]));
+test('mode multi-mode', () => assert.deepEqual(mode([1, 1, 2, 2, 3]), [1, 2]));
+test('mode single element', () => assert.deepEqual(mode([5]), [5]));
+test('mode throws on empty', () => assert.throws(() => mode([])));
+
+// utils
+test('slugify spaces', () => assert.equal(slugify('Hello World'), 'hello-world'));
+test('slugify special chars', () => assert.equal(slugify('  Foo & Bar!'), 'foo-bar'));
+test('slugify already fine', () => assert.equal(slugify('Already-fine'), 'already-fine'));
+
+test('capitalize basic', () => assert.equal(capitalize('hello world'), 'Hello world'));
+test('capitalize shouting', () => assert.equal(capitalize('SHOUTING'), 'Shouting'));
+test('capitalize empty', () => assert.equal(capitalize(''), ''));
+
+test('truncate long string', () => assert.equal(truncate('Hello world', 5), 'Hello...'));
+test('truncate short string', () => assert.equal(truncate('Hi', 10), 'Hi'));
+test('truncate custom suffix', () => assert.equal(truncate('Hello world', 5, '…'), 'Hello…'));
+
+test('camelCase spaces', () => assert.equal(camelCase('hello world'), 'helloWorld'));
+test('camelCase dashes', () => assert.equal(camelCase('foo-bar-baz'), 'fooBarBaz'));
+test('camelCase leading space', () => assert.equal(camelCase('  some string'), 'someString'));
